func testReportActionsSliceUpdateAll(t *testing.T) {
	t.Parallel()

	if len(reportActionAllColumns) == len(reportActionPrimaryKeyColumns) {
		t.Skip("Skipping table with only primary key columns")
	}

	seed := randomize.NewSeed()
	var err error
	o := &ReportAction{}
	if err = randomize.Struct(seed, o, reportActionDBTypes, true, reportActionColumnsWithDefault...); err != nil {
		t.Errorf("Unable to randomize ReportAction struct: %s", err)
	}

	ctx := context.Background()
	tx := MustTx(boil.BeginTx(ctx, nil))
	defer func() { _ = tx.Rollback() }()
	if err = o.Insert(ctx, tx, boil.Infer()); err != nil {
		t.Error(err)
	}

	count, err := ReportActions().Count(ctx, tx)
	if err != nil {
		t.Error(err)
	}

	if count != 1 {
		t.Error("want one record, got:", count)
	}

	if err = randomize.Struct(seed, o, reportActionDBTypes, true, reportActionPrimaryKeyColumns...); err != nil {
		t.Errorf("Unable to randomize ReportAction struct: %s", err)
	}

	// Remove Primary keys and unique columns from what we plan to update
	var fields []string
	if strmangle.StringSliceMatch(reportActionAllColumns, reportActionPrimaryKeyColumns) {
		fields = reportActionAllColumns
	} else {
		fields = strmangle.SetComplement(
			reportActionAllColumns,
			reportActionPrimaryKeyColumns,
		)
	}

	value := reflect.Indirect(reflect.ValueOf(o))
	typ := reflect.TypeOf(o).Elem()
	n := typ.NumField()

	updateMap := M{}
	for _, col := range fields {
		for i := 0; i < n; i++ {
			f := typ.Field(i)
			if f.Tag.Get("boil") == col {
				updateMap[col] = value.Field(i).Interface()
			}
		}
	}

	slice := ReportActionSlice{o}
	if rowsAff, err := slice.UpdateAll(ctx, tx, updateMap); err != nil {
		t.Error(err)
	} else if rowsAff != 1 {
		t.Error("wanted one record updated but got", rowsAff)
	}
}

func testReportActionsUpsert(t *testing.T) {
	t.Parallel()

	if len(reportActionAllColumns) == len(reportActionPrimaryKeyColumns) {
		t.Skip("Skipping table with only primary key columns")
	}

	seed := randomize.NewSeed()
	var err error
	// Attempt the INSERT side of an UPSERT
	o := ReportAction{}
	if err = randomize.Struct(seed, &o, reportActionDBTypes, true); err != nil {
		t.Errorf("Unable to randomize ReportAction struct: %s", err)
	}

	ctx := context.Background()
	tx := MustTx(boil.BeginTx(ctx, nil))
	defer func() { _ = tx.Rollback() }()
	if err = o.Upsert(ctx, tx, false, nil, boil.Infer(), boil.Infer()); err != nil {
		t.Errorf("Unable to upsert ReportAction: %s", err)
	}

	count, err := ReportActions().Count(ctx, tx)
	if err != nil {
		t.Error(err)
	}
	if count != 1 {
		t.Error("want one record, got:", count)
	}

	// Attempt the UPDATE side of an UPSERT
	if err = randomize.Struct(seed, &o, reportActionDBTypes, false, reportActionPrimaryKeyColumns...); err != nil {
		t.Errorf("Unable to randomize ReportAction struct: %s", err)
	}

	if err = o.Upsert(ctx, tx, true, nil, boil.Infer(), boil.Infer()); err != nil {
		t.Errorf("Unable to upsert ReportAction: %s", err)
	}

	count, err = ReportActions().Count(ctx, tx)
	if err != nil {
		t.Error(err)
	}
	if count != 1 {
		t.Error("want one record, got:", count)
	}
}
